SELECT COUNT(accident_id) 
FROM restraint_use 
WHERE type = 'seatbelt';

SELECT name
FROM investigators
WHERE years_of_experience > (SELECT AVG(years_of_experience) FROM investigators);

SELECT AVG(case_duration_days) AS average_duration
FROM case_details
WHERE status = 'Open';

SELECT type, COUNT(*) AS total_restraints 
FROM restraint_use 
GROUP BY type;
